import { useState } from 'react';
import Sidebar from '../layout/Sidebar';

const sg = '#00c471';
const sgd = '#009a58';
const sgl = '#e6f9f1';

// =============================================
// MemberManagement — 회원 관리
// =============================================
const MEMBERS = [
  { id: 1, name: '김지수', email: 'jisu@email.com', phone: '010-1234-5678', grade: 'VIP', orders: 28, amount: 842000, joined: '2024.03.12', status: '활성' },
  { id: 2, name: '이민준', email: 'minjun@email.com', phone: '010-2345-6789', grade: '일반', orders: 7, amount: 124500, joined: '2025.01.08', status: '활성' },
  { id: 3, name: '박서연', email: 'seoyeon@email.com', phone: '010-3456-7890', grade: 'VIP', orders: 45, amount: 1340000, joined: '2023.11.22', status: '활성' },
  { id: 4, name: '최현우', email: 'hyunwoo@email.com', phone: '010-4567-8901', grade: '일반', orders: 3, amount: 45200, joined: '2025.08.14', status: '활성' },
  { id: 5, name: '정유나', email: 'yuna@email.com', phone: '010-5678-9012', grade: '일반', orders: 12, amount: 213000, joined: '2024.09.30', status: '휴면' },
  { id: 6, name: '강민서', email: 'minseo@email.com', phone: '010-6789-0123', grade: 'VIP', orders: 33, amount: 987000, joined: '2024.01.05', status: '차단' },
];
const MEMBER_STATUS = { 활성: { bg: sgl, color: sgd }, 휴면: { bg: '#f1efe8', color: '#5f5e5a' }, 차단: { bg: '#fcebeb', color: '#a32d2d' } };
const GRADE_STYLE = { VIP: { bg: '#eeedfe', color: '#534ab7' }, 일반: { bg: '#f1efe8', color: '#5f5e5a' } };
const AVATAR_COLORS = [{ bg: sgl, color: sgd }, { bg: '#e6f1fb', color: '#185fa5' }, { bg: '#faeeda', color: '#854f0b' }, { bg: '#fbeaf0', color: '#993556' }, { bg: '#eeedfe', color: '#534ab7' }];

export function MemberManagement({ setPage }) {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [gradeFilter, setGradeFilter] = useState('');
  const [selected, setSelected] = useState(null);

  const filtered = MEMBERS.filter(m => {
    if (statusFilter && m.status !== statusFilter) return false;
    if (gradeFilter && m.grade !== gradeFilter) return false;
    if (search && !m.name.includes(search) && !m.email.includes(search) && !m.phone.includes(search)) return false;
    return true;
  });

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f5f5f3', fontFamily: 'sans-serif' }}>
      <Sidebar currentPage="adminPC_members" setPage={setPage} />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={s.topbar}><div style={s.topbarTitle}>회원 관리</div></div>
        <div style={s.content}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 10, marginBottom: 16 }}>
            {[{ label: '전체 회원', val: '1,284' }, { label: '활성 회원', val: '1,102', color: sgd }, { label: 'VIP', val: '87', color: '#534ab7' }, { label: '이번 달 신규', val: '42' }].map(c => (
              <div key={c.label} style={s.sumCard}><div style={s.sumLabel}>{c.label}</div><div style={{ fontSize: 17, fontWeight: 500, color: c.color || '#333' }}>{c.val}</div></div>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
            <input style={{ ...s.input, flex: 1 }} placeholder="이름, 이메일, 전화번호 검색..." value={search} onChange={e => setSearch(e.target.value)} />
            <select style={s.select} value={statusFilter} onChange={e => setStatusFilter(e.target.value)}><option value="">전체 상태</option>{['활성','휴면','차단'].map(v => <option key={v}>{v}</option>)}</select>
            <select style={s.select} value={gradeFilter} onChange={e => setGradeFilter(e.target.value)}><option value="">전체 등급</option><option>VIP</option><option>일반</option></select>
          </div>
          <div style={s.tableCard}>
            <table style={s.table}>
              <thead style={{ background: '#f5f5f3' }}>
                <tr>{['회원','연락처','등급','누적 주문','누적 금액','가입일','상태','관리'].map(h => <th key={h} style={s.th}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {filtered.map(m => {
                  const av = AVATAR_COLORS[m.id % AVATAR_COLORS.length];
                  return (
                    <tr key={m.id}>
                      <td style={s.td}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                          <div style={{ width: 32, height: 32, borderRadius: '50%', background: av.bg, color: av.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 500 }}>{m.name[0]}</div>
                          <div><div style={{ fontWeight: 500, fontSize: 12 }}>{m.name}</div><div style={{ fontSize: 10, color: '#aaa' }}>{m.email}</div></div>
                        </div>
                      </td>
                      <td style={{ ...s.td, color: '#666' }}>{m.phone}</td>
                      <td style={s.td}><span style={{ ...s.pill, ...GRADE_STYLE[m.grade] }}>{m.grade}</span></td>
                      <td style={{ ...s.td, fontWeight: 500 }}>{m.orders}건</td>
                      <td style={{ ...s.td, fontWeight: 500 }}>₩{m.amount.toLocaleString()}</td>
                      <td style={{ ...s.td, color: '#aaa', fontSize: 11 }}>{m.joined}</td>
                      <td style={s.td}><span style={{ ...s.pill, ...MEMBER_STATUS[m.status] }}>{m.status}</span></td>
                      <td style={s.td}><button style={s.actionBtn} onClick={() => setSelected(m)}>상세</button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {selected && (
        <div style={s.modalBg} onClick={() => setSelected(null)}>
          <div style={s.modal} onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18 }}>
              <span style={{ fontSize: 15, fontWeight: 500 }}>회원 상세</span>
              <button style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 18, color: '#888' }} onClick={() => setSelected(null)}>✕</button>
            </div>
            {[['이름', selected.name], ['이메일', selected.email], ['연락처', selected.phone], ['등급', selected.grade], ['누적 주문', `${selected.orders}건`], ['누적 결제', `₩${selected.amount.toLocaleString()}`], ['가입일', selected.joined], ['상태', selected.status]].map(([l, v]) => (
              <div key={l} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, padding: '7px 0', borderBottom: '0.5px solid #eee' }}>
                <span style={{ color: '#888' }}>{l}</span><span style={{ fontWeight: 500 }}>{v}</span>
              </div>
            ))}
            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 18 }}>
              <button style={s.btn} onClick={() => setSelected(null)}>닫기</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// =============================================
// ReviewManagement — 리뷰 관리
// =============================================
const INIT_REVIEWS = [
  { id: 1, name: '김지수', product: '유기농 사과', rating: 5, body: '정말 달고 신선해요! 포장도 꼼꼼하게 잘 돼있었고 배송도 빠르게 왔어요.', date: '2026.05.06', status: 'show', reply: '' },
  { id: 2, name: '이민준', product: '제주 삼다수 20L', rating: 4, body: '물 맛도 좋고 배송도 빨랐어요. 다만 박스가 살짝 찌그러져 왔는데 내용물은 이상 없었어요.', date: '2026.05.05', status: 'show', reply: '불편을 드려 죄송합니다. 다음에는 더 꼼꼼히 포장하겠습니다.' },
