                <td style={{ ...s.td, fontWeight: 500 }}>{a.name}</td>
                <td style={{ ...s.td, color: '#666' }}>{a.email}</td>
                <td style={s.td}><span style={{ ...s.pill, background: a.role === '슈퍼 어드민' ? '#eeedfe' : sgl, color: a.role === '슈퍼 어드민' ? '#534ab7' : sgd }}>{a.role}</span></td>
                <td style={{ ...s.td, color: '#aaa', fontSize: 11 }}>{a.last}</td>
                <td style={s.td}>{a.role !== '슈퍼 어드민' && <button style={{ ...s.actionBtn, color: '#a32d2d', borderColor: '#f09595' }}>삭제</button>}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>,
    <div key="danger">
      <div style={{ ...s.sectionCard, borderColor: '#f09595' }}>
        <div style={{ ...s.sectionTitle, color: '#a32d2d' }}>위험 구역</div>
        <ToggleRow label="쇼핑몰 임시 점검 모드" desc="활성화 시 고객에게 점검 중 안내 페이지 표시" k="maintenanceMode" />
        <ToggleRow label="신규 주문 일시 중지" desc="활성화 시 장바구니 및 결제 기능 비활성화" k="stopOrders" />
      </div>
    </div>,
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f5f5f3', fontFamily: 'sans-serif' }}>
      <Sidebar currentPage="adminPC_settings" setPage={setPage} />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={s.topbar}>
          <div style={s.topbarTitle}>설정</div>
          <button style={s.btnPrimary} onClick={() => alert('저장되었습니다!')}>변경사항 저장</button>
        </div>
        <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
          <div style={{ width: 180, borderRight: '0.5px solid #eee', background: '#fff', padding: '16px 0', flexShrink: 0 }}>
            {SETTING_PAGES.map((p, i) => (
              <div key={p} onClick={() => setActivePage(i)} style={{ padding: '9px 20px', fontSize: 13, cursor: 'pointer', borderLeft: `2px solid ${activePage === i ? sg : 'transparent'}`, color: activePage === i ? sgd : '#666', fontWeight: activePage === i ? 500 : 400, background: activePage === i ? sgl : 'transparent' }}>{p}</div>
            ))}
          </div>
          <div style={{ flex: 1, overflowY: 'auto', padding: 24 }}>{pages[activePage]}</div>
        </div>
      </div>
    </div>
  );
}

